  describe("quote - base premiums", () => {
    it("empty item list yields 5 G (processing fee only)", () => {
      expect(quote({ customer: { yearsWithMHPCO: 0 }, items: [] })).toEqual({ premium: 5 });
    });
    it("single sword yields 105 G (100 base + 5 fee)", () => {
      expect(quote({
        customer: { yearsWithMHPCO: 0 },
        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }]
      })).toEqual({ premium: 105 });
    });
    it("single amulet yields 65 G (60 base + 5 fee)", () => {
      expect(quote({
        customer: { yearsWithMHPCO: 0 },
        items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }]
      })).toEqual({ premium: 65 });
    });
    it("single staff yields 85 G (80 base + 5 fee)", () => {
      expect(quote({
        customer: { yearsWithMHPCO: 0 },
        items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }]
      })).toEqual({ premium: 85 });
    });
    it("single potion yields 45 G (40 base + 5 fee)", () => {
      expect(quote({
        customer: { yearsWithMHPCO: 0 },
        items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }]
      })).toEqual({ premium: 45 });
    });
    it("two swords sum base premiums: 205 G", () => {
      expect(quote({
        customer: { yearsWithMHPCO: 0 },
        items: [
          { type: "sword", material: "steel", enchantment: 0, cursed: false },
          { type: "sword", material: "steel", enchantment: 0, cursed: false }
        ]
      })).toEqual({ premium: 205 });
    });
    it("a sword and an amulet sum base premiums: 165 G", () => {
      expect(quote({
        customer: { yearsWithMHPCO: 0 },
        items: [
          { type: "sword", material: "steel", enchantment: 0, cursed: false },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false }
        ]
      })).toEqual({ premium: 165 });
    });
  });

  describe("quote - components and building blocks", () => {
    it("single rune yields 30 G (25 base + 5 fee)", () => {
      expect(quote({
        customer: { yearsWithMHPCO: 0 },
        items: [{ type: "rune" }]
      })).toEqual({ premium: 30 });
    });
    it("2 runes yield 55 G (50 base + 5 fee)", () => {
      expect(quote({
        customer: { yearsWithMHPCO: 0 },
        items: [{ type: "rune" }, { type: "rune" }]
      })).toEqual({ premium: 55 });
    });
    it("3 runes form a block yielding 65 G (60 base + 5 fee)", () => {
      expect(quote({
        customer: { yearsWithMHPCO: 0 },
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }]
      })).toEqual({ premium: 65 });
    });
    it("4 runes yield 105 G (100 base + 5 fee, no block)", () => {
      expect(quote({
        customer: { yearsWithMHPCO: 0 },
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }]
      })).toEqual({ premium: 105 });
    });
    it("7 runes yield 180 G (175 base + 5 fee, 7 individual)", () => {
      expect(quote({
        customer: { yearsWithMHPCO: 0 },
        items: Array.from({ length: 7 }, () => ({ type: "rune" }))
      })).toEqual({ premium: 180 });
    });
    it("2 runes + 1 moonstone yield 80 G (75 base + 5 fee, no block)", () => {
      expect(quote({
        customer: { yearsWithMHPCO: 0 },
        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }]
      })).toEqual({ premium: 80 });
    });
    it.todo("3 runes + 3 moonstones yield 125 G (120 base + 5 fee, two blocks)");
  });

  describe("quote - premium modifiers", () => {
    it.todo("cursed sword adds 50% surcharge to that item");
    it.todo("highly enchanted sword (level 5) adds 30% surcharge");
    it.todo("enchantment level 4 does not trigger high-enchantment surcharge");
    it.todo("loyalty discount (2+ years) reduces 20% from policy base");
    it.todo("first insurance adds 10% per item");
    it.todo("follow-up contract gives 15% discount on policy base");
    it.todo("modifiers stack: newcomer with cursed sword yields 165 G");
    it.todo("long-standing customer second contract with cursed enchanted sword yields 160 G");
  });

  describe("quote - rounding", () => {
    it.todo("premium fractions round up (in MHPCO's favor)");
  });

  describe("claim - basic payout", () => {
    it.todo("standard sword damage 500 G yields 400 G payout (minus 100 deductible)");
    it.todo("rune damage 200 G yields 100 G payout");
    it.todo("damage to high-enchantment item (level 8+) reimbursed at 50%");
    it.todo("damage to dragon-material item fully reimbursed");
    it.todo("dragon-material high-enchantment item: 50% rule wins then deductible");
    it.todo("deductible applies per damaged item, not per claim");
    it.todo("payout capped at twice insurance sum");
    it.todo("successive claims: remaining cap decreases");
  });

  describe("claim - cap", () => {
    it.todo("policy cap is twice the sum of items' insurance values");
    it.todo("component blocks do not affect insurance sum (still 250 G each)");
  });

  describe("CLI", () => {
    it.todo("processes a scenario with quote and claim steps");
    it.todo("unknown item type causes non-zero exit");
    it.todo("claim referencing item not in policy causes non-zero exit");
    it.todo("negative damage amount causes non-zero exit");
  });
});

