const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;
const COMPONENT_BASE = 25;
const FIRST_INS_SURCHARGE = 0.1;
const CURSE_SURCHARGE = 0.5;
const HIGH_ENCH_SURCHARGE = 0.3;
const HIGH_ENCH_THRESHOLD = 5;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_THRESHOLD = 2;
const FOLLOW_UP_DISCOUNT = 0.15;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = {
  type: string;
  enchantment?: number;
  cursed?: boolean;
  material?: string;
};

const baseForItem = (item: Item): number =>
  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;

const isComponent = (item: Item): boolean =>
  COMPONENT_TYPES.has(item.type);

const itemModifierSum = (item: Item): number => {
  let mod = FIRST_INS_SURCHARGE;
  if (item.cursed) mod += CURSE_SURCHARGE;
  if ((item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD) mod += HIGH_ENCH_SURCHARGE;
  return mod;
};

const itemCharge = (item: Item): number =>
  baseForItem(item) * (1 + itemModifierSum(item));

const countByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

const componentsCharge = (items: Item[]): number => {
  const componentItems = items.filter(isComponent);
  const counts = countByType(componentItems);
  let total = 0;
  for (const type in counts) {
    const count = counts[type];
    if (count === BLOCK_SIZE) {
      total += BLOCK_PRICE * (1 + FIRST_INS_SURCHARGE);
    } else {
      total += count * COMPONENT_BASE * (1 + FIRST_INS_SURCHARGE);
    }
  }
  return total;
};

const componentsBase = (items: Item[]): number => {
  const componentItems = items.filter(isComponent);
  const counts = countByType(componentItems);
  let total = 0;
  for (const type in counts) {
    const count = counts[type];
    total += count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_BASE;
  }
  return total;
};

const nonComponentsCharge = (items: Item[]): number =>
  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + itemCharge(item), 0);

const nonComponentsBase = (items: Item[]): number =>
  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + baseForItem(item), 0);

export function quote(input: any): unknown {
  const items: Item[] = input.items;
  const itemTotal = nonComponentsCharge(items) + componentsCharge(items);
  const policyBase = nonComponentsBase(items) + componentsBase(items);
  const years = input.customer?.yearsWithMHPCO ?? 0;
  let policyModifiers = 0;
  if (years >= LOYALTY_THRESHOLD) policyModifiers -= LOYALTY_DISCOUNT;
  if (input.isFollowUp) policyModifiers -= FOLLOW_UP_DISCOUNT;
  const policyAdjustment = policyBase * policyModifiers;
  const raw = itemTotal + policyAdjustment + PROCESSING_FEE;
  const premium = Math.ceil(Math.round(raw * 1e8) / 1e8);
  return { premium };
}

export function claim(input: any): unknown {
  let payout = 0;
  for (const damageEntry of input.incident.damages) {
    const item = input.policy.items.find((i: Item) => i.type === damageEntry.itemType);
    let amount = damageEntry.amount;
    if (item && (item.enchantment ?? 0) >= 8) {
      amount = amount * 0.5;
    }
    payout += amount - 100;
  }
  payout = Math.min(payout, input.policy.remainingCap);
  const remainingCap = input.policy.remainingCap - payout;
  return { payout, remainingCap };
}

